SELECT n.request_id, COUNT(n.notification_id) AS total_notifications
FROM notifications n
GROUP BY n.request_id;

SELECT service_name, service_type_id
FROM service_types
WHERE service_type_id NOT IN (
    SELECT DISTINCT service_type_id
    FROM service_requests
);

SELECT *
FROM service_requests
ORDER BY estimated_completion_date;

SELECT 
    (SELECT COUNT(DISTINCT service_type_id) FROM service_types) AS unique_service_types,
    (SELECT COUNT(DISTINCT category_id) FROM service_categories) AS unique_service_categories;

SELECT COUNT(*) 
FROM user_requests 
WHERE user_id = (SELECT user_id FROM users WHERE email = 'alice.johnson@example.com');

SELECT DISTINCT u.name, u.email
FROM users u
JOIN notifications n ON u.user_id = n.sent_by_id;
